     * the MK, so this is a fresh wrap under `new_prf` (multi-device add).
     */override fun `rewrap`(`newPrf`: kotlin.ByteArray): WrappedBlob {
            return FfiConverterTypeWrappedBlob.lift(
    callWithPointer {
