     * and IV (12B) are generated in-core with the CSPRNG — no nonce-reuse footgun.
     */override fun `wrapWithPrf`(`prf`: kotlin.ByteArray): WrappedBlob {
            return FfiConverterTypeWrappedBlob.lift(
    callWithPointer {
    uniffiRustCall() { _status ->
    UniffiLib.INSTANCE.uniffi_braird_core_fn_method_vault_wrap_with_prf(
