    @Throws(CryptoException::class) fun `redeemPinTransfer`(`transferBlob`: WrappedBlob, `pin`: kotlin.String): Vault {
            return FfiConverterTypeVault.lift(
    uniffiRustCallWithError(CryptoException) { _status ->
